<circle cx="490" cy="105" r="6" fill="none" stroke="currentColor" stroke-width="2"/>
<text x="502" y="109" font-size="13" fill="currentColor">Censored (t = 20)</text>
<line x1="140" y1="150" x2="560" y2="150" stroke="currentColor" stroke-width="1"/>
